module DescribeOpsItemsResponse =
  struct
    type nonrec t =
      {
      nextToken: String_.t option ;
      opsItemSummaries: OpsItemSummaries.t option }
    type nonrec error =
      [ `InternalServerError of InternalServerError.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?nextToken =
      fun ?opsItemSummaries -> fun () -> { nextToken; opsItemSummaries }
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("NextToken", (Option.map x.nextToken ~f:String_.to_value));
        ("OpsItemSummaries",
          (Option.map x.opsItemSummaries ~f:OpsItemSummaries.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let opsItemSummaries =
        (Option.map ~f:OpsItemSummaries.of_xml)
          (Xml.child xml_arg0 "OpsItemSummaries") in
      let nextToken =
        (Option.map ~f:String_.of_xml) (Xml.child xml_arg0 "NextToken") in
      make ?opsItemSummaries ?nextToken ()
    let of_json json =
      let opsItemSummaries =
        field_map json "OpsItemSummaries" OpsItemSummaries.of_json in
      let nextToken = field_map json "NextToken" String_.of_json in
