module DescribeParametersResult =
  struct
    type nonrec t =
      {
      parameters: ParameterMetadataList.t option ;
      nextToken: NextToken.t option }
    type nonrec error =
      [ `InternalServerError of InternalServerError.t 
      | `InvalidFilterKey of InvalidFilterKey.t 
      | `InvalidFilterOption of InvalidFilterOption.t 
      | `InvalidFilterValue of InvalidFilterValue.t 
      | `InvalidNextToken of InvalidNextToken.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?parameters =
      fun ?nextToken -> fun () -> { parameters; nextToken }
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "InvalidFilterKey" ->
          `InvalidFilterKey (InvalidFilterKey.of_json json)
      | "InvalidFilterOption" ->
          `InvalidFilterOption (InvalidFilterOption.of_json json)
      | "InvalidFilterValue" ->
          `InvalidFilterValue (InvalidFilterValue.of_json json)
      | "InvalidNextToken" ->
          `InvalidNextToken (InvalidNextToken.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "InvalidFilterKey" -> `InvalidFilterKey (InvalidFilterKey.of_xml xml)
      | "InvalidFilterOption" ->
          `InvalidFilterOption (InvalidFilterOption.of_xml xml)
      | "InvalidFilterValue" ->
          `InvalidFilterValue (InvalidFilterValue.of_xml xml)
      | "InvalidNextToken" -> `InvalidNextToken (InvalidNextToken.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `InvalidFilterKey e ->
          `Assoc
            [("error", (`String "InvalidFilterKey"));
            ("details", (InvalidFilterKey.to_json e))]
      | `InvalidFilterOption e ->
          `Assoc
            [("error", (`String "InvalidFilterOption"));
            ("details", (InvalidFilterOption.to_json e))]
      | `InvalidFilterValue e ->
          `Assoc
            [("error", (`String "InvalidFilterValue"));
            ("details", (InvalidFilterValue.to_json e))]
      | `InvalidNextToken e ->
          `Assoc
            [("error", (`String "InvalidNextToken"));
            ("details", (InvalidNextToken.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Parameters",
           (Option.map x.parameters ~f:ParameterMetadataList.to_value));
        ("NextToken", (Option.map x.nextToken ~f:NextToken.to_value))]
    let to_query v = to_query to_value v
