      [ `InternalServerError of InternalServerError.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?properties =
      fun ?nextToken -> fun () -> { properties; nextToken }
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Properties",
           (Option.map x.properties ~f:PatchPropertiesList.to_value));
        ("NextToken", (Option.map x.nextToken ~f:NextToken.to_value))]
