module GetAutomationExecutionResult =
  struct
    type nonrec t = {
      automationExecution: AutomationExecution.t option }
    type nonrec error =
      [
        `AutomationExecutionNotFoundException of
          AutomationExecutionNotFoundException.t 
      | `InternalServerError of InternalServerError.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?automationExecution = fun () -> { automationExecution }
    let error_of_json name json =
      match name with
      | "AutomationExecutionNotFoundException" ->
          `AutomationExecutionNotFoundException
            (AutomationExecutionNotFoundException.of_json json)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AutomationExecutionNotFoundException" ->
          `AutomationExecutionNotFoundException
            (AutomationExecutionNotFoundException.of_xml xml)
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AutomationExecutionNotFoundException e ->
          `Assoc
            [("error", (`String "AutomationExecutionNotFoundException"));
            ("details", (AutomationExecutionNotFoundException.to_json e))]
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("AutomationExecution",
           (Option.map x.automationExecution ~f:AutomationExecution.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let automationExecution =
        (Option.map ~f:AutomationExecution.of_xml)
          (Xml.child xml_arg0 "AutomationExecution") in
      make ?automationExecution ()
    let of_json json =
      let automationExecution =
        field_map json "AutomationExecution" AutomationExecution.of_json in
      make ?automationExecution ()
    let to_json v = composed_to_json to_value v
  end
