module GetInventoryResult =
  struct
    type nonrec t =
      {
      entities: InventoryResultEntityList.t option ;
      nextToken: NextToken.t option }
    type nonrec error =
      [ `InternalServerError of InternalServerError.t 
      | `InvalidAggregatorException of InvalidAggregatorException.t 
      | `InvalidFilter of InvalidFilter.t 
      | `InvalidInventoryGroupException of InvalidInventoryGroupException.t 
      | `InvalidNextToken of InvalidNextToken.t 
      | `InvalidResultAttributeException of InvalidResultAttributeException.t 
      | `InvalidTypeNameException of InvalidTypeNameException.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?entities = fun ?nextToken -> fun () -> { entities; nextToken }
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "InvalidAggregatorException" ->
          `InvalidAggregatorException
            (InvalidAggregatorException.of_json json)
      | "InvalidFilter" -> `InvalidFilter (InvalidFilter.of_json json)
      | "InvalidInventoryGroupException" ->
          `InvalidInventoryGroupException
            (InvalidInventoryGroupException.of_json json)
      | "InvalidNextToken" ->
          `InvalidNextToken (InvalidNextToken.of_json json)
      | "InvalidResultAttributeException" ->
          `InvalidResultAttributeException
            (InvalidResultAttributeException.of_json json)
      | "InvalidTypeNameException" ->
          `InvalidTypeNameException (InvalidTypeNameException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "InvalidAggregatorException" ->
          `InvalidAggregatorException (InvalidAggregatorException.of_xml xml)
      | "InvalidFilter" -> `InvalidFilter (InvalidFilter.of_xml xml)
      | "InvalidInventoryGroupException" ->
          `InvalidInventoryGroupException
            (InvalidInventoryGroupException.of_xml xml)
      | "InvalidNextToken" -> `InvalidNextToken (InvalidNextToken.of_xml xml)
      | "InvalidResultAttributeException" ->
          `InvalidResultAttributeException
            (InvalidResultAttributeException.of_xml xml)
      | "InvalidTypeNameException" ->
          `InvalidTypeNameException (InvalidTypeNameException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `InvalidAggregatorException e ->
          `Assoc
            [("error", (`String "InvalidAggregatorException"));
            ("details", (InvalidAggregatorException.to_json e))]
      | `InvalidFilter e ->
          `Assoc
            [("error", (`String "InvalidFilter"));
            ("details", (InvalidFilter.to_json e))]
      | `InvalidInventoryGroupException e ->
          `Assoc
            [("error", (`String "InvalidInventoryGroupException"));
            ("details", (InvalidInventoryGroupException.to_json e))]
      | `InvalidNextToken e ->
          `Assoc
            [("error", (`String "InvalidNextToken"));
            ("details", (InvalidNextToken.to_json e))]
      | `InvalidResultAttributeException e ->
          `Assoc
            [("error", (`String "InvalidResultAttributeException"));
            ("details", (InvalidResultAttributeException.to_json e))]
      | `InvalidTypeNameException e ->
          `Assoc
            [("error", (`String "InvalidTypeNameException"));
            ("details", (InvalidTypeNameException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("Entities",
           (Option.map x.entities ~f:InventoryResultEntityList.to_value));
        ("NextToken", (Option.map x.nextToken ~f:NextToken.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let nextToken =
        (Option.map ~f:NextToken.of_xml) (Xml.child xml_arg0 "NextToken") in
      let entities =
        (Option.map ~f:InventoryResultEntityList.of_xml)
          (Xml.child xml_arg0 "Entities") in
      make ?nextToken ?entities ()
    let of_json json =
      let nextToken = field_map json "NextToken" NextToken.of_json in
      let entities =
        field_map json "Entities" InventoryResultEntityList.of_json in
      make ?nextToken ?entities ()
    let to_json v = composed_to_json to_value v
  end
