module LabelParameterVersionResult =
  struct
    type nonrec t =
      {
      invalidLabels: ParameterLabelList.t option ;
      parameterVersion: PSParameterVersion.t option }
    type nonrec error =
      [ `InternalServerError of InternalServerError.t 
      | `ParameterNotFound of ParameterNotFound.t 
      | `ParameterVersionLabelLimitExceeded of
          ParameterVersionLabelLimitExceeded.t 
      | `ParameterVersionNotFound of ParameterVersionNotFound.t 
      | `TooManyUpdates of TooManyUpdates.t 
      | `Unknown_operation_error of (string * string option) ]
    let make ?invalidLabels =
      fun ?parameterVersion -> fun () -> { invalidLabels; parameterVersion }
    let error_of_json name json =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_json json)
      | "ParameterNotFound" ->
          `ParameterNotFound (ParameterNotFound.of_json json)
      | "ParameterVersionLabelLimitExceeded" ->
          `ParameterVersionLabelLimitExceeded
            (ParameterVersionLabelLimitExceeded.of_json json)
      | "ParameterVersionNotFound" ->
          `ParameterVersionNotFound (ParameterVersionNotFound.of_json json)
      | "TooManyUpdates" -> `TooManyUpdates (TooManyUpdates.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "InternalServerError" ->
          `InternalServerError (InternalServerError.of_xml xml)
      | "ParameterNotFound" ->
          `ParameterNotFound (ParameterNotFound.of_xml xml)
      | "ParameterVersionLabelLimitExceeded" ->
          `ParameterVersionLabelLimitExceeded
            (ParameterVersionLabelLimitExceeded.of_xml xml)
      | "ParameterVersionNotFound" ->
          `ParameterVersionNotFound (ParameterVersionNotFound.of_xml xml)
      | "TooManyUpdates" -> `TooManyUpdates (TooManyUpdates.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `InternalServerError e ->
          `Assoc
            [("error", (`String "InternalServerError"));
            ("details", (InternalServerError.to_json e))]
      | `ParameterNotFound e ->
          `Assoc
            [("error", (`String "ParameterNotFound"));
            ("details", (ParameterNotFound.to_json e))]
      | `ParameterVersionLabelLimitExceeded e ->
          `Assoc
            [("error", (`String "ParameterVersionLabelLimitExceeded"));
            ("details", (ParameterVersionLabelLimitExceeded.to_json e))]
      | `ParameterVersionNotFound e ->
          `Assoc
            [("error", (`String "ParameterVersionNotFound"));
            ("details", (ParameterVersionNotFound.to_json e))]
      | `TooManyUpdates e ->
          `Assoc
            [("error", (`String "TooManyUpdates"));
            ("details", (TooManyUpdates.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("InvalidLabels",
           (Option.map x.invalidLabels ~f:ParameterLabelList.to_value));
        ("ParameterVersion",
          (Option.map x.parameterVersion ~f:PSParameterVersion.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let parameterVersion =
        (Option.map ~f:PSParameterVersion.of_xml)
          (Xml.child xml_arg0 "ParameterVersion") in
      let invalidLabels =
        (Option.map ~f:ParameterLabelList.of_xml)
          (Xml.child xml_arg0 "InvalidLabels") in
      make ?parameterVersion ?invalidLabels ()
    let of_json json =
      let parameterVersion =
        field_map json "ParameterVersion" PSParameterVersion.of_json in
      let invalidLabels =
        field_map json "InvalidLabels" ParameterLabelList.of_json in
      make ?parameterVersion ?invalidLabels ()
    let to_json v = composed_to_json to_value v
  end
